func monitorPausePath(monitorID int64) string {
	return monitorDetailPath(monitorID) + "/pause"
}

func monitorResumePath(monitorID int64) string {
	return monitorDetailPath(monitorID) + "/resume"
}

func monitorDeletePath(monitorID int64) string {
	return monitorDetailPath(monitorID) + "/delete"
}

func monitorEditPath(monitorID int64) string {
	return monitorDetailPath(monitorID) + "/edit"
}

// monitorToggleAction — куда шлёт форма Pause/Resume: enabled монитор
// паузится, paused — резюмируется. Один и тот же <button> текстом отражает
// действие, которое произойдёт при нажатии, не текущее состояние.
func monitorToggleAction(m uptime.Monitor) string {
	if m.Enabled {
		return monitorPausePath(m.ID)
	}
	return monitorResumePath(m.ID)
}

func checkStatusText(ok bool) string {
	if ok {
		return "ok"
	}
	return "fail"
}

// sslExpiryText — "—" без сертификата (не https-монитор или ещё не было ни
// одной успешной https-проверки), иначе дней до истечения + дата;
// отрицательный остаток (сертификат уже просрочен) — отдельным словом, не
// "-3d left".
func sslExpiryText(t *time.Time) string {
	if t == nil {
		return "—"
	}
	days := int(time.Until(*t).Hours() / 24)
	if days < 0 {
		return "expired (" + t.Format("2006-01-02") + ")"
	}
	return strconv.Itoa(days) + "d left (" + t.Format("2006-01-02") + ")"
}

// incidentDurationText — "ongoing" для ещё не закрытого инцидента, иначе
// длительность между started_at и resolved_at.
func incidentDurationText(inc uptime.Incident) string {
	if inc.ResolvedAt == nil {
		return "ongoing"
	}
	return inc.ResolvedAt.Sub(inc.StartedAt).String()
}

func yesNo(b bool) string {
	if b {
		return "yes"
	}
	return "no"
}

// heartbeatPingURL/heartbeatCronSnippet — те же вычисления, что и одноимённые
// функции в web/monitorform.go; собственная копия здесь, а не импорт
// web-пакета — templates не может импортировать web (иначе цикл: web ->
// templates -> web).
func heartbeatPingURL(baseURL, token string) string {
	return baseURL + "/uptime/hb/" + token
}

func heartbeatCronSnippet(baseURL, token string, intervalSeconds int) string {
	minutes := intervalSeconds / 60
	if minutes < 1 {
		minutes = 1
	}
	return "*/" + strconv.Itoa(minutes) + " * * * * curl -fsS " + heartbeatPingURL(baseURL, token) + " >/dev/null"
}

